import { Navbar } from '@/components/layout/Navbar'
import { SearchBar } from './components/SearchBar'
import { FilterSidebar } from './components/FilterSidebar'
import { JobSections } from './components/JobSections'

export default function JobsPage() {
  return (
    <div className="min-h-screen bg-[#f7f3ef]">
      <Navbar />

      {/* ── Hero Header ─────────────────────────────────────────────── */}
      <div className="relative overflow-hidden border-b border-[#d4c4b5] ">

        {/* Background texture dots */}
        <div className="absolute inset-0 opacity-[0.03]"
          style={{
            backgroundImage: 'radial-gradient(#4a3728 1px, transparent 1px)',
            backgroundSize: '24px 24px',
          }}
        />

        {/* Warm gradient blobs */}
        <div className="absolute top-[-60px] right-[-60px] w-72 h-72 rounded-full bg-[#e0d8cf] opacity-40 blur-3xl pointer-events-none" />
        <div className="absolute bottom-[-40px] left-[10%] w-56 h-56 rounded-full bg-[#d4c4b5] opacity-30 blur-3xl pointer-events-none" />

        <div className="relative max-w-7xl mx-auto px-6 py-14">
          <div className="max-w-2xl">

            {/* Eyebrow */}
            <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-[#4a3728]/[0.07] border border-[#4a3728]/10 mb-5">
              <span className="w-1.5 h-1.5 rounded-full bg-[#4a3728] animate-pulse" />
              <span className="text-[#4a3728] text-xs font-semibold tracking-wide">
                {new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric' })} · New roles added daily
              </span>
            </div>

            {/* Main heading */}
            <h1 className="text-[42px] font-black text-[#4a3728] leading-[1.1] tracking-tight">
              Find Your Next
              <br />
              <span className="relative inline-block mt-1">
                <span className="relative z-10">Opportunity.</span>
                {/* Underline highlight */}
                <svg className="absolute -bottom-1 left-0 w-full" viewBox="0 0 300 12" fill="none" preserveAspectRatio="none">
                  <path d="M2 9 C60 3, 140 3, 298 8" stroke="#d4c4b5" strokeWidth="6" strokeLinecap="round" />
                </svg>
              </span>
            </h1>

            <p className="text-[#6b5847] text-base mt-4 leading-relaxed max-w-lg">
              Discover roles at the most ambitious companies building the future —
              from seed-stage startups to category-defining giants.
            </p>

            {/* Compact search row */}
            <div className="mt-7 flex items-center gap-2.5">
              <div className="flex items-center gap-2 bg-white border border-[#d4c4b5] rounded-xl px-4 py-2.5 w-60
                focus-within:border-[#4a3728]/40 shadow-sm transition-colors">
                <svg className="w-4 h-4 text-[#6b5847] shrink-0" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
                <input type="text" placeholder="Role or skill..."
                  className="flex-1 bg-transparent text-[#4a3728] placeholder:text-[#6b5847]/40 text-sm font-medium outline-none" />
              </div>

              <div className="flex items-center gap-2 bg-white border border-[#d4c4b5] rounded-xl px-4 py-2.5 w-44
                focus-within:border-[#4a3728]/40 shadow-sm transition-colors">
                <svg className="w-4 h-4 text-[#6b5847] shrink-0" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                </svg>
                <input type="text" placeholder="Location..."
                  className="flex-1 bg-transparent text-[#4a3728] placeholder:text-[#6b5847]/40 text-sm font-medium outline-none" />
              </div>

              <button className="px-5 py-2.5 bg-[#4a3728] hover:bg-[#3a2a1e] text-[#e0d8cf] text-sm font-bold rounded-xl
                transition-colors active:scale-[0.98] shadow-sm shrink-0">
                Search
              </button>
            </div>

            {/* Popular tags */}
            <div className="mt-4 flex items-center gap-2 flex-wrap">
              <span className="text-xs text-[#6b5847]/50 font-medium">Trending:</span>
              {['Product Designer', 'Frontend Engineer', 'Remote', 'AI / ML', 'Senior'].map((tag) => (
                <button key={tag}
                  className="text-xs px-2.5 py-1 rounded-lg bg-[#f7f3ef] border border-[#d4c4b5] text-[#6b5847]
                    hover:text-[#4a3728] hover:border-[#4a3728]/20 hover:bg-[#e0d8cf]/50 transition-colors font-medium">
                  {tag}
                </button>
              ))}
            </div>

          </div>

          {/* Right side stats */}
          <div className="absolute right-6 bottom-8 hidden lg:flex items-end gap-8">
            {[
              { number: '200+', label: 'Open Roles' },
              { number: '80+',  label: 'Companies'  },
              { number: '12k+', label: 'Applicants' },
            ].map(({ number, label }) => (
              <div key={label} className="text-right">
                <p className="text-2xl font-black text-[#4a3728]">{number}</p>
                <p className="text-xs text-[#6b5847] font-medium mt-0.5">{label}</p>
              </div>
            ))}
          </div>

        </div>
      </div>

      {/* ── Main content ─────────────────────────────────────────────── */}
      <main className="max-w-7xl mx-auto px-6 py-8">
        <div className="flex gap-6 items-start">
          <FilterSidebar />
          <div className="flex-1 min-w-0">
            <JobSections />
          </div>
        </div>
      </main>

    </div>
  )
}